import React, { useState } from "react";
import { motion } from "framer-motion";

export function ShowcaseCarousel() {
  const [index, setIndex] = useState(0);

  const items = [
    {
      title: "Chat App",
      description: "Real-time messaging app with modern UI",
      image: "https://picsum.photos/400/600",
      live: "#",
      code: "#",
    },
    {
      title: "Finance Tracker",
      description: "Track expenses and analytics",
      image: "https://picsum.photos/400/600",
      live: "#",
      code: "#",
    },
  ];

  const next = () => setIndex((prev) => (prev + 1) % items.length);
  const prev = () => setIndex((prev) => (prev - 1 + items.length) % items.length);

  const current = items[index];

  return (
    <div className="min-h-screen flex flex-col items-center justify-center px-4 bg-black text-white">

      {/* Title */}
      <h2 className="text-2xl md:text-4xl font-bold mb-10 text-center">
        My Projects
      </h2>

      {/* Card Wrapper */}
      <div className="relative">

        {/* Glow Background */}
        <div className="absolute inset-0 blur-2xl opacity-30 bg-gradient-to-r from-indigo-500 to-purple-500 rounded-3xl"></div>

        {/* Card */}
        <motion.div
          key={index}
          initial={{ opacity: 0, y: 40, scale: 0.95 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          transition={{ duration: 0.5 }}
          className="relative w-[300px] sm:w-[340px] md:w-[380px] bg-white/10 border border-white/20 backdrop-blur-xl rounded-3xl shadow-2xl overflow-hidden"
        >
          {/* Image */}
          <div className="overflow-hidden">
            <img
              src={current.image}
              alt={current.title}
              className="w-full h-[200px] object-cover transition duration-500 hover:scale-110"
            />
          </div>

          {/* Content */}
          <div className="p-5">
            <h3 className="text-xl font-semibold">
              {current.title}
            </h3>

            <p className="text-gray-300 text-sm mt-2">
              {current.description}
            </p>

            {/* Buttons */}
            <div className="flex gap-3 mt-4">
              <a href={current.live} target="_blank" rel="noreferrer">
                <button className="px-4 py-2 text-sm rounded-lg bg-indigo-500 hover:bg-indigo-600 transition shadow-lg shadow-indigo-500/40">
                  Live
                </button>
              </a>

              <a href={current.code} target="_blank" rel="noreferrer">
                <button className="px-4 py-2 text-sm rounded-lg border border-indigo-400 text-indigo-400 hover:bg-indigo-500 hover:text-white transition">
                  Code
                </button>
              </a>
            </div>
          </div>
        </motion.div>
      </div>

      {/* Navigation */}
      <div className="flex items-center gap-12 mt-8">
        <button
          onClick={prev}
          className="px-4 py-2 rounded-full bg-white/10 border border-white/20 hover:bg-indigo-500 transition hover:scale-105"
        >
          ←
        </button>

        <button
          onClick={next}
          className="px-4 py-2 rounded-full bg-indigo-500 hover:bg-indigo-600 transition shadow-lg shadow-indigo-500/40 hover:scale-105"
        >
          →
        </button>
      </div>

      {/* Dots */}
      <div className="flex gap-2 mt-6">
        {items.map((_, i) => (
          <div
            key={i}
            onClick={() => setIndex(i)}
            className={`h-2.5 w-2.5 rounded-full cursor-pointer transition ${
              i === index ? "bg-indigo-500 scale-125" : "bg-gray-500"
            }`}
          />
        ))}
      </div>
    </div>
  );
}
